// Extract remoteJid, messageType, and group classification
const body = $json.body || $json;
const data = body.data || {};
const key = data.key || {};
const jid = key.remoteJid || '';
const isGroup = jid.endsWith('@g.us');
const messageType = data.messageType || '';
const isImage = messageType === 'imageMessage';
const fromMe = !!key.fromMe;
const isComprobantes = jid === '120363409525696846@g.us';
return [{ json: { ...body, _isGroup: isGroup, _jid: jid, _isImage: isImage, _fromMe: fromMe, _isComprobantes: isComprobantes } }];

// Extract image base64 and sender info
const data = $json.data || {};
const key = data.key || {};
const msg = data.message || {};
const base64 = msg.base64 || msg.imageMessage?.base64 || '';
if (!base64 || base64.length < 100) throw new Error('No image data');
const rawPhone = (key.remoteJid || '').replace('@s.whatsapp.net', '');
return [{ json: { base64, phone: rawPhone, pushName: data.pushName || '', caption: msg.imageMessage?.caption || '' } }];

// Parse GPT Vision response - check if Zelle
const gptRaw = $json.choices?.[0]?.message?.content || '';
const imgData = $('Z: Extract image').first().json;
let parsed;
try {
  const clean = gptRaw.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
  parsed = JSON.parse(clean);
} catch(e) { throw new Error("NOT_ZELLE"); }

if (!parsed.is_zelle) throw new Error("NOT_ZELLE");
if (!parsed.amount || parsed.amount <= 0) throw new Error("No amount");

return [{ json: {
  amount: parsed.amount,
  reference: parsed.reference || "sin-ref",
  date: parsed.date || new Date().toISOString().split("T")[0],
  senderName: parsed.sender_name || "",
  phone: imgData.phone,
  pushName: imgData.pushName
}}];

// Build cash_movement and dashboard msg
const parsed = $('Z: Check Zelle').first().json;
const orderResult = $('Z: Find order').first().json;
const order = Array.isArray(orderResult) ? orderResult[0] : orderResult;
const hasOrder = !!(order && order.id);

const cashBody = {
  movement_type: 'ingreso', wallet: 'zelle',
  amount: parsed.amount, amount_usd_equivalent: parsed.amount,
  concept: 'Zelle ' + (hasOrder ? '#' + order.order_number : 'sin pedido') + ' - ' + (parsed.senderName || parsed.pushName || 'cliente') + (parsed.reference !== 'sin-ref' ? ' ref:' + parsed.reference : ''),
  order_id: hasOrder ? order.id : null
};

let dashMsg = '\u2705 Zelle $' + parsed.amount;
if (hasOrder) dashMsg += ' ' + (order.client_name || parsed.pushName) + ' #' + order.order_number + ' \u2014 registrado.';
else dashMsg += ' ' + (parsed.pushName || 'cliente') + ' (tel: ' + parsed.phone + ') \u2014 registrado. \u26a0\ufe0f Sin pedido pendiente.';

return [{ json: { cashBody, dashMsg, hasOrder, orderId: hasOrder ? order.id : null, amount: parsed.amount } }];

// Extract image from group comprobantes message
const data = $json.data || {};
const key = data.key || {};
const msg = data.message || {};
const base64 = msg.base64 || msg.imageMessage?.base64 || '';
if (!base64 || base64.length < 100) throw new Error('No image data');
const participant = key.participant || key.participantAlt || '';
const phone = participant.replace('@s.whatsapp.net', '').replace(/@lid$/, '');
const caption = msg.imageMessage?.caption || '';
return [{ json: { base64, phone, pushName: data.pushName || '', caption, sourceGroup: 'comprobantes' } }];

