// Parse GPT response + get order from caption or pending context (5min window)
const gptRaw = $json.choices?.[0]?.message?.content || '';
const imgData = $('C: Extract image').first().json;

let parsed;
try {
  const clean = gptRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) { throw new Error('NOT_PAYMENT'); }

if (!parsed.payment_type || parsed.payment_type === 'unknown') throw new Error('NOT_PAYMENT');
if (!parsed.amount || parsed.amount <= 0) throw new Error('No amount extracted');

const walletMap = { zelle: 'zelle', pago_movil: 'bolivares', transferencia: 'bolivares', binance: 'binance' };
const wallet = walletMap[parsed.payment_type] || 'zelle';
const typeNames = { zelle: 'Zelle', pago_movil: 'Pago Movil', transferencia: 'Transferencia', binance: 'Binance' };
const typeName = typeNames[parsed.payment_type] || parsed.payment_type;
const currency = parsed.currency || (wallet === 'bolivares' ? 'BS' : 'USD');

// 1) Try caption
const captionMatch = (imgData.caption || '').match(/#(\d+)/);
let orderNumber = captionMatch ? captionMatch[1] : null;

// 2) If no caption, check pending context (must be < 5 min old)
if (!orderNumber) {
  const pendingResult = $('C: Fetch pending').first().json;
  const pending = Array.isArray(pendingResult) ? pendingResult[0] : pendingResult;
  if (pending && pending.product_name) {
    const age = Date.now() - new Date(pending.created_at).getTime();
    if (age < 5 * 60 * 1000) {
      orderNumber = pending.product_name;
    }
  }
}

return [{ json: {
  paymentType: parsed.payment_type, typeName, wallet,
  amount: parsed.amount, currency,
  reference: parsed.reference || null,
  date: parsed.date || new Date().toISOString().split('T')[0],
  bank: parsed.bank || null,
  phone: imgData.phone, pushName: imgData.pushName,
  caption: imgData.caption, orderNumber
}}];

// Build cash_movement + dashboard message with order linking
const parsed = $('C: Parse receipt').first().json;
const rate = $('C: Fetch rate').first().json.Bs || 1;
const orderResult = $('C: Find order').first().json;
const order = Array.isArray(orderResult) ? orderResult[0] : orderResult;
const hasOrder = !!(order && order.id);

let amount = parsed.amount;
let amountUsdEq = parsed.currency === 'BS' ? Math.round((amount / rate) * 100) / 100 : amount;

const cashBody = {
  movement_type: 'ingreso',
  wallet: parsed.wallet,
  amount: amount,
  exchange_rate: rate,
  amount_usd_equivalent: amountUsdEq,
  concept: parsed.typeName + (hasOrder ? ' #' + order.order_number + ' - ' + order.client_name : '') + (parsed.reference ? ' ref:' + parsed.reference : ''),
  order_id: hasOrder ? order.id : null
};

let dashMsg = '\u2705 ' + parsed.typeName;
if (parsed.currency === 'BS') dashMsg += ' Bs ' + amount.toLocaleString() + ' (~$' + amountUsdEq + ')';
else dashMsg += ' $' + amount;

if (hasOrder) {
  dashMsg += ' \u2014 ' + order.client_name + ' #' + order.order_number + ' \u2014 registrado. Pedido confirmado.';
} else {
  dashMsg += (parsed.reference ? ' ref:' + parsed.reference : '') + ' \u2014 registrado. \u26a0\ufe0f Sin pedido. Responde: pagado #XXXX ' + parsed.wallet + ' $' + amount;
}

return [{ json: { cashBody, dashMsg, hasOrder, orderId: hasOrder ? order.id : null, orderNumber: parsed.orderNumber, wallet: parsed.wallet, amountUsdEq } }];

